css:
.loader {color: var(--loader-color, #0f766e);
  --loader-secondary-color: #5eead4;
  --loader-bg: #ffffff;
  width: 60px;
  height: 30px;
  display: grid;
  --c: #0000 calc(100% - 5px),currentColor calc(100% - 4px) 96%,#0000;
  background:radial-gradient(farthest-side at bottom,var(--c)) 0 0,radial-gradient(farthest-side at top ,var(--c)) 100% 100%;
  background-size: calc(50% + 2px) 50%;
  background-repeat: no-repeat;
  animation: l14 1.5s infinite linear;
}.loader:before,.loader:after {content: "";
  grid-area: 1/1;
  background: inherit;
  animation: inherit;
  animation-duration: 2s;
}.loader:before {--s:-1;
}@keyframes l14 {100% {transform: scale(calc(var(--s,1)*1turn))}}
